document.addEventListener("DOMContentLoaded",(()=>{async function handleFormSubmit(e){const t={},l=[];document.querySelectorAll(".card-body").forEach((e=>{e.querySelectorAll("input, select, textarea").forEach((e=>{if("INPUT"===e.tagName&&e.hasAttribute("readonly"))t[e.name]=e.value;else if("INPUT"===e.tagName)if("checkbox"===e.type)t[e.name]=e.checked;else if("date"===e.type&&""===e.value)t[e.name]=null;else if("time"===e.type&&""===e.value)t[e.name]=null;else if("number"===e.type&&""===e.value)t[e.name]=0;else if("file"===e.type&&e.files.length>0){const s=new Promise(((l,s)=>{const c=new FileReader;c.onload=function(s){t[e.name]=s.target.result,l()},c.onerror=s,c.readAsDataURL(e.files[0])}));l.push(s)}else t[e.name]=e.value;else if("TEXTAREA"===e.tagName)t[e.name]=e.value;else if("SELECT"===e.tagName)if(e.multiple){const l=Array.from(e.selectedOptions).map((e=>e.value));t[e.name]=l.length>0?l:[]}else t[e.name]=-1===e.selectedIndex?null:e.options[e.selectedIndex].value}))}));try{await Promise.all(l);const e=await Swal.fire({title:"Επιλογή αρχείων για ενημέρωση",html:'\n                <div class="col-8 left-align checkbox-flex-center">\n                    <input type="checkbox" class="form-check-input custom-checkbox checkbox-class" id="employees" name="files" value="employees" checked />\n                    <label for="employees" id="label-employees" class="ml0_75-fs-0_875vw">\n                    Στοιχεία Εργαζόμενων\n                    </label><br>\n                </div>\n                <div class="col-8 left-align checkbox-flex-center">\n                    <input type="checkbox" class="form-check-input custom-checkbox checkbox-class" id="schedules" name="files" value="schedules" checked />\n                    <label for="schedules" id="label-schedules" class="ml0_75-fs-0_875vw">\n                    Ωράρια ( ΕΡΓΑΝΗ ΙΙ )\n                    </label><br>\n                </div>\n                <div class="col-8 left-align checkbox-flex-center">\n                    <input type="checkbox" class="form-check-input custom-checkbox checkbox-class" id="history" name="files" value="history" checked />\n                    <label for="history" id="label-history" class="ml0_75-fs-0_875vw">\n                    Ιστορικό Προσλήψεων - Αλλαγών Συμβάσεων\n                    </label><br>\n                </div>',focusConfirm:!1,preConfirm:()=>({employees:document.getElementById("employees").checked,schedules:document.getElementById("schedules").checked,history:document.getElementById("history").checked}),confirmButtonText:"Ενημέρωση",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title"}}),s=await fetch("/ergazomenoi/ergazomenoi/add",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({formData:t,filesToUpdate:e.value})});if(!s.ok)throw new Error(`HTTP error! status: ${s.status}`);const c=await s.json();if(c.success){let t="<ul>";e.value.employees&&(t+='<li><i class="bi bi-check-lg cgreen"></i> Εργαζομένων</li>'),e.value.schedules&&(t+='<li><i class="bi bi-check-lg cgreen"></i> Ωραρίων</li>'),e.value.history&&(t+='<li><i class="bi bi-check-lg cgreen"></i> Ιστορικού Προσλήψεων - Αλλαγών</li>'),t+="</ul>",Swal.fire({icon:"success",title:"Επιτυχής ενημέρωση των αρχείων:",html:t,timer:1500,confirmButtonText:"Κλείσιμο",customClass:{title:"custom-title",popup:"custom-swal-popup",confirmButton:"class-success custom-confirm-button custom-swal-button"}}).then((()=>{window.location.href=c.redirectUrl}))}else await Swal.fire({icon:"error",title:"Προσοχή",html:c.errorMessage,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title"}})}catch(e){console.error("Σφάλμα:",e),Swal.fire("Σφάλμα","Σφάλμα κατά τη διαδικασία ενημέρωσης: "+e.message,"error")}}document.querySelectorAll(".submitButton").forEach((e=>{e.addEventListener("click",handleFormSubmit)}))}));